#include <stdio.h>
int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        int A,B,C,D;
        scanf("%d %d", &A, &B);
        scanf("%d %d", &C, &D);
        if(C>=A && D>=B) printf("POSSIBLE\n");
        else printf("IMPOSSIBLE\n");
    }
    return 0;
}

